Here's a complete implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*">
                    <Image Source="{Binding Icon}"
                           WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1"
                           Text="{Binding Name}"
                           VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <ContentView>
                <Label Text="No items found."
                       HorizontalOptions="Center"
                       VerticalOptions="Center" />
            </ContentView>
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigation _navigation;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ICommand RefreshCommand { get; }
    public ICommand ItemSelectedCommand { get; }

    public ItemsViewModel(IApiService api, INavigation navigation)
    {
        _api = api;
        _navigation = navigation;

        RefreshCommand = new AsyncRelayCommand(RefreshDataAsync);
        ItemSelectedCommand = new RelayCommand(OnItemSelected);
    }

    private async Task RefreshDataAsync()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;   // stops the spinner
    }

    private void OnItemSelected()
    {
        if (CurrentItem is null) return;
        _navigation.PushAsync(new DetailPage(CurrentItem));
        CurrentItem = null;     // reset so user can re-select
    }
}
```

### Key bindings explained

| Property | Purpose |
|---|---|
| `IsRefreshing` (TwoWay) | Drives the refresh spinner; set `false` when done |
| `RefreshCommand` | Fires on pull-down; reloads from API |
| `SelectedItem` → `CurrentItem` (TwoWay) | Tracks the tapped item |
| `SelectionChangedCommand` | Fires on tap; navigates then nulls `CurrentItem` |
| `ItemsSource` → `ObservableCollection<Item>` | Must be `ObservableCollection`, not `List`, so the UI updates on add/remove |

**Important notes:**
- Always set `IsRefreshing = false` after loading — otherwise the spinner stays.
- Null out `CurrentItem` after navigation so the same item can be re-selected.
- Update the collection on the **UI thread** via `MainThread.BeginInvokeOnMainThread`.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
